import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e}from"./app-5b8a6393.js";const o={},c=e(`<h2 id="_1-var-키워드로-선언한-변수의-문제점" tabindex="-1"><a class="header-anchor" href="#_1-var-키워드로-선언한-변수의-문제점" aria-hidden="true">#</a> 1. var 키워드로 선언한 변수의 문제점</h2><p>ES5까지 변수를 선언할 수 있는 유일한 방법은 <code>var</code> 키워드를 사용하는 것이었다.<br> var 키워드로 선언된 변수는 다음과 같은 특징이 있다.</p><h3 id="_1-1-변수-중복-선언-허용" tabindex="-1"><a class="header-anchor" href="#_1-1-변수-중복-선언-허용" aria-hidden="true">#</a> 1.1. 변수 중복 선언 허용</h3><p><code>var</code> 키워드로 선언한 변수는 중복 선언이 가능하다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
<span class="token keyword">var</span> y <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token comment">// var 키워드로 선언된 변수는 같은 스코프 내에서 중복 선언이 허용한다.</span>
<span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>

<span class="token comment">// 초기화문이 없는 변수 선언문은 무시된다.</span>
<span class="token keyword">var</span> y<span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>y<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 예제의 <code>var</code> 키워드로 선언한 x와 y 변수는 중복 선언되었다. 이처럼 <code>var</code> 키워드로 선언한 변수를 중복 선언하면 초기화문 유무에 따라 다르게 동작한다.</p><h3 id="_1-2-함수-레벨-스코프" tabindex="-1"><a class="header-anchor" href="#_1-2-함수-레벨-스코프" aria-hidden="true">#</a> 1.2. 함수 레벨 스코프</h3><p><code>var</code> 키워드로 선언한 변수는 오로지 함수의 코드 블록만을 지역 스코프로 인정한다.<br> 따라서 함수 외부에서 <code>var</code> 키워드로 선언한 변수는 코드 블록 내에서 선언해도 모두 전역 변수가 된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>for 문의 변수 선언문에서 <code>var</code> 키워드로 선언한 변수도 전역 변수가 된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 0 1 2 3 4</span>
<span class="token punctuation">}</span>

<span class="token comment">// 의도치 않게 i 변수의 변수 값이 변경되었다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 5</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>함수 레벨 스코프는 전역 변수를 남발할 가능성을 높인다.</p><h3 id="_1-3-변수-호이스팅" tabindex="-1"><a class="header-anchor" href="#_1-3-변수-호이스팅" aria-hidden="true">#</a> 1.3. 변수 호이스팅</h3><p><code>var</code> 키워드로 변수를 선언하면 변수 호이스팅에 의해 변수 선언문이 선두로 끌어 올려진 것처럼 동작한다.<br> 단, 할당문 이전에 변수를 참조하면 언제나 <code>undefined</code>를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//undefined</span>

foo <span class="token operator">=</span> <span class="token number">123</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 123</span>

<span class="token keyword">var</span> foo<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>변수 선언문 이전에 변수를 참조하는 것은 변수 호이스팅에 의해 에러를 발생시키지는 않지만 프로그램 흐름상 맞지 않을 뿐더러 가독성을 떨어뜨리고 오류를 발생할 여지를 남긴다.</p><h2 id="_2-let-키워드" tabindex="-1"><a class="header-anchor" href="#_2-let-키워드" aria-hidden="true">#</a> 2. let 키워드</h2><p>앞에서 살펴본 <code>var</code> 키워드의 단점을 보완하기 위해 ES6에서는 새로운 변수 선언 키워드인 <code>let</code>과 <code>const</code>를 도입했다.<br><code>var</code> 키워드와의 차이점을 중심으로 <code>let</code> 키워드를 살펴보자.</p><h3 id="_2-1-변수-중복-선언-금지" tabindex="-1"><a class="header-anchor" href="#_2-1-변수-중복-선언-금지" aria-hidden="true">#</a> 2.1. 변수 중복 선언 금지</h3><p>let 키워드로 이름이 같은 변수를 중복 선언하면 문법 에러(SyntaxError)가 발생한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> foo <span class="token operator">=</span> <span class="token number">123</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> foo <span class="token operator">=</span> <span class="token number">456</span><span class="token punctuation">;</span>

<span class="token keyword">let</span> bar <span class="token operator">=</span> <span class="token number">123</span><span class="token punctuation">;</span>
<span class="token comment">// let이나 const 키워드로 선언된 변수는 스코프 내에서 중복 선언을 허용하지 않는다.</span>
<span class="token keyword">let</span> bar <span class="token operator">=</span> <span class="token number">456</span><span class="token punctuation">;</span> <span class="token comment">// SyntaxError: Identifier &#39;bar&#39; has already been declared</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-블록-레벨-스코프" tabindex="-1"><a class="header-anchor" href="#_2-2-블록-레벨-스코프" aria-hidden="true">#</a> 2.2. 블록 레벨 스코프</h3><p><code>let</code> 키워드로 선언한 변수는 모든 코드 블록(함수, if, for, while, try/catch 문 등)을 지역 스코프로 인정하는 블록 레벨 스코프를 따른다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">// 전역 변수</span>

<span class="token punctuation">{</span>
  <span class="token keyword">let</span> foo <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// 지역 변수</span>
  <span class="token keyword">let</span> bar <span class="token operator">=</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token comment">// 지역 변수</span>
<span class="token punctuation">}</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>bar<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError: bar is not defined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>전역에서 선언된 foo 변수와 코드 블록 내에서 선언된 foo 변수는 다른 별개의 변수다.<br> 또한 bar 변수도 블록 레벨 스코프를 갖는 지역 변수다. 따라서 전역에서는 bar 변수를 참조할 수 없다.<br> 함수도 코드 블록이므로 스코프를 만든다. 이때 함수 내의 코드 블록은 함수 레벨 스코프에 중첩된다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/129ef772-183a-4054-b4ee-4aec10e09a84" alt="그림 15-1. 블록 레벨 스코프의 중첩" tabindex="0" loading="lazy"><figcaption>그림 15-1. 블록 레벨 스코프의 중첩</figcaption></figure><h3 id="_2-3-변수-호이스팅" tabindex="-1"><a class="header-anchor" href="#_2-3-변수-호이스팅" aria-hidden="true">#</a> 2.3. 변수 호이스팅</h3><p>var 키워드로 선언한 변수와 달리 let 키워드로 선언한 변수는 변수 호이스팅이 발생하지 않는 것처럼 동작한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError: foo is not defined</span>
<span class="token keyword">let</span> foo<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>let</code> 키워드로 선언한 변수를 변수 선언문 이전에 참조하면 참조 에러가 발생한다.<br> 4.3절 &quot;변수 선언&quot;에서 살펴본 바와 같이 <code>var</code> 키워드로 선언한 변수는 런타임 이전에 자바스크립트 엔진에 의해 암묵적으로 &quot;선언 단계&quot;와 &quot;초기화 단계&quot;가 한번에 진행된다.</p><p>따라서 변수 선언문 이전에 변수에 접근해도 스코프에 변수가 존재하기 때문에 에러가 발생하지 않는다.<br> 다만 <code>undefined</code>를 반환한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">var</span> foo<span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span>

foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/bf40fa6e-57f8-483d-9352-4334d352df03" alt="그림 15-2. var 키워드로 선언한 변수의 생명 주기" tabindex="0" loading="lazy"><figcaption>그림 15-2. var 키워드로 선언한 변수의 생명 주기</figcaption></figure><p><code>let</code> 키워드로 선언한 변수는 &quot;선언 단계&quot;와 &quot;초기화 단계&quot;가 분리되어 진행된다.<br> 런타임 이전에 자바스크립트 엔진에 의해 암묵적으로 선언 단계가 실행되지만 초기화 단계는 변수 선언문에 도달 했을 때 실행된다.</p><p>스코프의 시작 지점부터 초기화 시작 지점까지 변수를 참조할 수 없는 구간을 일시적 사각지대(TDZ: Temporal Dead Zone)라고 부른다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 선언 단계 실행. 초기화 x</span>
<span class="token comment">// 일시적 사각지대</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError: foo is not defined</span>

<span class="token keyword">let</span> foo<span class="token punctuation">;</span> <span class="token comment">// 변수 선언문에서 초기화 단계 실행</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>

foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">// 할당문에서 할당 단계 실행</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/61f5f0d6-c5b7-4dda-b95e-6122a7d06c96" alt="그림 15-3. let 키워드로 선언한 변수의 생명 주기" tabindex="0" loading="lazy"><figcaption>그림 15-3. let 키워드로 선언한 변수의 생명 주기</figcaption></figure><p><code>let</code> 키워드로 선언한 변수는 변수 호이스팅이 발생하지 않는 것처럼 보인다. 하지만 그렇지 않다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token comment">// 전역 변수</span>

<span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError: Cannot access &#39;foo&#39; before initialization</span>
  <span class="token keyword">let</span> foo <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// 지역 변수</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>let</code> 키워드로 선언한 변수의 경우 변수 호이스팅이 발생하지 않는다면 위 예제는 전역 변수 foo의 값을 출력해야한다.</p><p>하지만 <code>let</code> 키워드로 선언한 변수도 여전히 호이스팅이 발생하기 때문에 참조 에러(ReferenceError)가 발생한다.</p><p>자바스크립트는 ES6에서 도입된 <code>let</code>, <code>const</code>를 포함해서 모든 선언(<code>var</code>, <code>let</code>, <code>const</code>, <code>function</code>, <code>function*</code>, <code>class</code> 등)을 호이스팅 한다.</p><p>단, <code>let</code>, <code>const</code>, <code>class</code>를 사용한 선언문은 호이스팅이 발생하지 않는 것처럼 동작한다.</p><h3 id="_2-4-전역-객체와-let" tabindex="-1"><a class="header-anchor" href="#_2-4-전역-객체와-let" aria-hidden="true">#</a> 2.4. 전역 객체와 let</h3><p><code>var</code> 키워드로 선언한 전역 변수와 전역 함수, 그리고 선언하지 않은 변수에 값을 할당한 암묵적 전역은 전역 객체 window의 프로퍼티가 된다. 전역 객체의 프로퍼티를 참조할 때 window를 생략할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 브라우저 환경에서 실행</span>

<span class="token comment">// 전역 변수</span>
<span class="token keyword">var</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

<span class="token comment">// 암묵적 전역</span>
y <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span>

<span class="token comment">// 전역 함수</span>
<span class="token keyword">function</span> <span class="token function">foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>y<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 2</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>y<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 2</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// f foo() {}</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// f foo() {}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>let</code> 키워드로 선언한 전역 변수는 전역 객체의 프로퍼티가 아니다. 즉, <code>window.foo</code>와 같이 접근할 수 없다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-const-키워드" tabindex="-1"><a class="header-anchor" href="#_3-const-키워드" aria-hidden="true">#</a> 3. const 키워드</h2><p><code>const</code>는 상수를 선언하기 위해 사용한다. 하지만 반드시 상수만을 위해 사용하지는 않는다<br><code>const</code> 키워드의 특징은 <code>let</code> 키워드와 대부분 동일하므로 <code>let</code> 키워드와 다른 점을 중심으로 살펴보자.</p><h3 id="_3-1-선언과-초기화" tabindex="-1"><a class="header-anchor" href="#_3-1-선언과-초기화" aria-hidden="true">#</a> 3.1. 선언과 초기화</h3><p><code>const</code> 키워드로 선언한 변수는 반드시 선언과 동시에 초기화 해야한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>그렇지 않으면 다음과 같이 문법 에러가 발생한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> foo<span class="token punctuation">;</span> <span class="token comment">// SyntaxError: Missing initializer in const declaration</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>const</code>로 선언한 변수는 <code>let</code> 키워드로 선언한 변수와 마찬가지로 블록 레벨 스코프를 가지며, 변수 호이스팅이 발생하지 않는 것처럼 동작한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError: Cannot access &#39;foo&#39; before initialization</span>
  <span class="token keyword">const</span> foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1</span>
<span class="token punctuation">}</span>

<span class="token comment">// 블록 레벨 스코프를 갖는다.</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>foo<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// ReferenceError: foo is not defined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-재할당-금지" tabindex="-1"><a class="header-anchor" href="#_3-2-재할당-금지" aria-hidden="true">#</a> 3.2. 재할당 금지</h3><p><code>var</code> 또는 <code>let</code> 키워드로 선언한 변수는 재할당이 자유로우나 <code>const</code> 키워드로 선언한 변수는 재할당이 금지된다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> foo <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
foo <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token comment">// TypeError: Assignment to constant varialbe</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-3-상수" tabindex="-1"><a class="header-anchor" href="#_3-3-상수" aria-hidden="true">#</a> 3.3. 상수</h3><p>변수의 상대 개념인 <strong>상수는 재할당이 금지된 변수를 말한다.</strong> 상수도 값을 저장하기 위한 메모리 공간이 필요하므로 변수라고 할 수 있다.<br> 단, 변수는 언제든지 재할당을 통해 변수 값을 변경할 수 있지만 상수는 재할당이 금지된다.</p><p>상수는 상태 유지와 가독성, 유지보수의 편의를 위해 적극적으로 사용해야한다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> preTaxPrice <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>

<span class="token keyword">let</span> afterTaxPrice <span class="token operator">=</span> preTaxPrice <span class="token operator">+</span> preTaxPrice <span class="token operator">*</span> <span class="token number">0.1</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>afterTaxPrice<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 110</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>코드 내에서 사용한 0.1은 어떤 의미로 사용했는지 명확히 알기 어렵기 때문에 가독성이 좋지 않다.<br> 이 때 세율을 상수로 정의하면 값의 의미를 쉽게 파악하고 변경될 수 없는 고정값으로 사용할 수 있다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> <span class="token constant">TAX_RATE</span> <span class="token operator">=</span> <span class="token number">0.1</span><span class="token punctuation">;</span>

<span class="token keyword">let</span> preTaxPrice <span class="token operator">=</span> <span class="token number">100</span><span class="token punctuation">;</span>

<span class="token keyword">let</span> afterTaxPrice <span class="token operator">=</span> preTaxPrice <span class="token operator">+</span> preTaxPrice <span class="token operator">*</span> <span class="token constant">TAX_RATE</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>afterTaxPrice<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 110</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-4-const-키워드와-객체" tabindex="-1"><a class="header-anchor" href="#_3-4-const-키워드와-객체" aria-hidden="true">#</a> 3.4 const 키워드와 객체</h3><p><strong><code>const</code> 키워드로 선언된 변수에 객체를 할당한 경우 값을 변경할 수 있다.</strong><br> 변경 불가능한 값인 원시 값은 재할당 없이 변경할 수 있는 방법이 없지만<br> 변경 가능한 값인 객체는 재할당 없이도 직접 변경이 가능하기 때문이다.</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> person <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Lee&quot;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

person<span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&quot;Kim&quot;</span><span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>person<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// {name: &quot;Kim&quot;}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>const</code> 키워드는 재할당을 금지할 뿐 &quot;불변&quot;을 의미하지 않는다.</strong><br> 다시 말해, 새로운 값을 재할당하는 것은 불가능하지만 프로퍼티 동적 생성, 삭제, 프로퍼티 값의 변경을 통해 객체를 변경하는 것은 가능하다. 이떄 객체가 변경되더라도 변수에 할당한 참조 값은 변경되지 않는다.</p><h2 id="_4-var-vs-let-vs-const" tabindex="-1"><a class="header-anchor" href="#_4-var-vs-let-vs-const" aria-hidden="true">#</a> 4. <code>var</code> vs. <code>let</code> vs. <code>const</code></h2><p>변수 선언에는 기본적으로 <code>const</code>를 사용하고 <code>let</code>은 재할당이 필요한 경우에 한정해 사용하는 것이 좋다.<br><code>const</code> 키워드를 사용하면 의도치 않은 재할당을 방지하기 때문에 좀 더 안전하다.</p><p><code>var</code>와 <code>let</code>, <code>const</code> 키워드는 다음과 같이 사용하는 것을 권장한다.</p><ul><li>ES6을 사용한다면 <code>var</code> 키워드는 사용하지 않는다.</li><li>재할당이 필요한 경우에 한정해 <code>let</code> 키워드를 사용한다. 이때 변수의 스코프는 최대한 좁게 만든다.</li><li>변경이 발생하지 않고 읽기 전용으로 사용하는 원시 값(재할당이 필요 없는 상수)과 객체에는 <code>const</code> 키워드를 사용한다.<br><code>const</code> 키워드는 재할당을 금지하므로 <code>var</code>, <code>let</code> 키워드 보다 안전하다.</li></ul><p>변수를 선언하는 시점에는 재할당이 필요할지 잘 모르는 경우가 많다. 그리고 객체는 의외로 재할당하는 경우가 드물다.</p><p>따라서 변수를 선언할 때는 일단 <code>const</code> 키워드를 사용하자. 반드시 재할당이 필요하다면 그때 <code>const</code> 키워드를 <code>let</code> 키워드로 변경해도 결코 늦지 않다.</p>`,76),t=[c];function p(i,l){return s(),a("div",null,t)}const r=n(o,[["render",p],["__file","deepdive15.html.vue"]]);export{r as default};
